  'ganzhou/orange': ('간난 배꼽오렌지', '붉은 토양에서 자란 이곳의 배꼽오렌지는 중국에서 가장 달콤하기로 유명해요.'),
  'ganzhou/house': ('객가 토루', '객가 사람들은 수 세기 동안 독특한 원형 요새 주택인 토루에서 살아왔어요.'),
  'ganzhou/pavilion': ('위구정', '송나라 시인들이 노래했던 이 정자에서는 두 강이 만나는 절경을 내려다볼 수 있어요.'),
  'ganzhou/star': ('대장정', '중국 홍군의 대장정이 바로 이 도시에서 시작되었어요.'),
  'putian/shrine': ('마조묘', '뱃사람의 수호신인 마조 여신이 태어난 곳으로, 메이저우섬에 본당이 자리하고 있어요.'),
  'putian/lychee': ('리치 과수원', '천 년 된 리치 나무들이 가득해 이 도시는 \'리치의 고장\'이라는 별명을 얻었어요.'),
  'putian/shoe': ('신발의 도시', '전 세계 운동화의 상당수가 이곳의 공장에서 생산되고 있어요.'),
  'putian/wave': ('메이저우섬', '페리를 타고 들어갈 수 있는 이 섬은 아름다운 해변과 사원 축제로 유명해요.'),
  'mudanjiang/snow': ('중국 설향', '겨울이면 두꺼운 눈이 쌓여 마치 동화 속 마을처럼 환상적인 풍경을 자아내요.'),
  'mudanjiang/lake': ('징포호', '화산 활동으로 형성된 호수로, 겨울에도 댜오수이러우 폭포가 웅장하게 쏟아져요.'),
  'mudanjiang/tiger': ('시베리아 호랑이 공원', '세계에서 가장 큰 시베리아 호랑이 보호구역 중 하나예요.'),
  'mudanjiang/ski': ('스키 시즌', '길고 눈이 많이 내리는 겨울 덕분에 스키 애호가들에게 인기 있는 여행지예요.'),
  'changzhou/dino': ('공룡원', '중국에서 가장 유명한 공룡 테마파크로, 가족 단위 여행객에게 사랑받는 명소예요.'),
  'changzhou/pagoda': ('톈닝사 탑', '높이 153미터에 달하는 세계에서 가장 높은 탑이 도심 한가운데 솟아 있어요.'),
  'changzhou/comb': ('빗 공예', '천 년의 역사를 자랑하는 창저우의 빗은 과거 왕실에 진상되던 귀한 선물이었어요.'),
  'changzhou/canal': ('대운하', '운하를 따라 걷다 보면 옛 거리의 정취와 화려한 야경을 함께 즐길 수 있어요.'),
  'shaoxing/wine': ('사오싱주', '중국 요리에 빠질 수 없는 유명한 황주가 수천 년 동안 이곳에서 빚어져 왔어요.'),
  'shaoxing/bridge': ('돌다리', '운하가 발달한 사오싱에는 수백 개의 아치형 돌다리가 그대로 보존되어 있어요.'),
  'shaoxing/pen': ('서예의 성지', '서예가 왕희지가 머물렀던 난팅은 서예를 공부하는 사람들에게 성지와 같은 곳이에요.'),
  'shaoxing/boat': ('우펑선', '발로 노를 저어 움직이는 검은 지붕의 우펑선은 운하를 즐기는 가장 고전적인 방법이에요.'),
  'bengbu/shell': ('진주의 항구', '지명 자체가 \'조개 부두\'를 뜻하며, 과거 화이허강의 진주로 명성이 높았어요.'),
  'bengbu/train': ('철도 교통의 요충지', '남북을 잇는 철도 노선이 화이허 강을 건너는 곳으로, 벵부라는 도시는 이 기차역과 함께 성장했습니다.'),
  'bengbu/river': ('화이허 강', '중국의 남북을 가르는 기준이 되는 화이허 강이 바로 이곳을 흐릅니다.'),
  'bengbu/blossom': ('봄꽃 축제', '매년 봄이 되면 강변 공원마다 화사한 꽃들이 피어나 축제가 열립니다.'),
  'jiujiang/mountain': ('루산', '유네스코 세계유산으로 등재된 루산의 안개 낀 봉우리는 수많은 시인과 화가들에게 영감을 주었습니다.'),
  'jiujiang/tea': ('윈우차', '루산의 비탈에서 자라는 윈우차는 중국에서 가장 섬세한 맛을 자랑하는 차 중 하나입니다.'),
  'jiujiang/lake': ('포양호', '중국 최대의 담수호인 포양호는 겨울철이 되면 수천 마리의 두루미가 찾아오는 철새 도래지입니다.'),
  'jiujiang/scroll': ('시의 도시', '백거이와 소식 같은 대문호들이 이곳 강변에서 아름다운 시 구절을 남겼습니다.'),
  'quanzhou/ship': ('해상 실크로드', '마르코 폴로가 \'자이툰\'이라 불렀던 이곳은 중세 시대 세계 최대의 항구였으며 유네스코 세계유산으로 지정되었습니다.'),
  'quanzhou/mosque': ('칭징사', '1009년에 세워진 이 돌로 만든 이슬람 사원은 중국에서 가장 오래된 사원 중 하나입니다.'),
  'quanzhou/puppet': ('꼭두각시 인형극', '취안저우의 줄 인형극은 천 년의 역사를 이어온 전통 공연 예술입니다.'),
  'quanzhou/tea': ('철관음', '인근 안시 지역에서 생산되는 우롱차인 철관음은 세계적으로 유명한 차입니다.'),
  'shanghai/pearl': ('동방명주', '황푸강 위로 솟아오른 분홍색 구체가 특징인 이 타워는 현대 상하이의 상징입니다.'),
  'shanghai/bund': ('와이탄', '강변을 따라 늘어선 역사적인 건물들과 호텔들은 옛 상하이의 웅장함을 그대로 보여줍니다.'),
  'shanghai/garden': ('예원', '명나라 시대에 지어진 전통 정원으로, 바위와 연못이 어우러져 도심 속 오아시스 같은 휴식처가 되어줍니다.'),
  'shanghai/xlb': ('샤오룽바오', '뜨거운 육즙을 가득 머금은 찜 요리인 샤오룽바오는 상하이 아침 식사의 정수입니다.'),
  'hangzhou/lake': ('시후', '버드나무와 작은 섬, 아치형 다리가 어우러진 시후는 중국 시인들에게 가장 많은 찬사를 받은 호수예요.'),
  'hangzhou/tea': ('롱징차', '호수 주변 비탈에서 재배되는 \'용정차\'는 중국에서 가장 유명한 녹차로 손꼽혀요.'),
  'hangzhou/temple': ('링인사', '1,700년의 역사를 자랑하는 링인사는 정교한 암벽 조각과 거대한 불상으로 유명한 사찰이에요.'),
  'hangzhou/silk': ('실크 시티', '천 년의 역사를 지닌 항저우의 비단은 실크로드 동쪽 끝을 풍요롭게 만들었던 귀한 특산물이에요.'),
  'chongqing/hongya': ('훙야둥', '절벽을 따라 세워진 독특한 건축물인 훙야둥은 밤이 되면 강 위로 동화 같은 야경을 선사해요.'),
  'chongqing/hotpot': ('충칭 훠궈', '얼얼하고 매콤한 기름이 끓어오르는 훠궈는 산악 도시 충칭의 뜨거운 영혼과도 같아요.'),
  'chongqing/monorail': ('충칭 모노레일', '건물 사이를 관통하며 달리는 모노레일은 언덕 위에 세워진 충칭만의 상징적인 풍경이에요.'),
  'chongqing/river': ('양쯔강 싼샤', '두 강이 만나는 지점에 자리한 충칭 항구에서는 양쯔강의 웅장한 협곡을 둘러보는 크루즈 여행이 시작돼요.'),
  'dalian/square': ('싱하이 광장', '아시아에서 가장 큰 도시 광장인 싱하이 광장은 바닷가를 따라 다양한 축제와 공연이 펼쳐지는 곳이에요.'),
  'dalian/beach': ('다롄 해변', '바위로 둘러싸인 해안과 시원한 여름 날씨 덕분에 다롄은 중국 북부에서 가장 사랑받는 휴양지예요.'),
  'dalian/football': ('축구 도시', '중국 축구의 요람이라 불리는 다롄은 수많은 명문 구단을 배출한 축구의 도시예요.'),
  'dalian/seafood': ('해산물 요리', '황해의 차가운 바다에서 건져 올린 가리비, 새우, 성게는 다롄 식탁을 풍성하게 채워줘요.'),
  'shenyang/palace': ('선양 고궁', '청나라의 첫 번째 궁궐인 선양 고궁은 베이징 자금성의 축소판 같은 매력을 지니고 있어요.'),
  'shenyang/tomb': ('청나라 황릉', '도시를 둘러싸고 있는 동릉과 북릉은 청나라를 세운 황제들의 웅장한 무덤이에요.'),
  'shenyang/factory': ('산업의 요람', '중국 중공업의 발상지인 선양은 거대한 공장들이 밀집해 있어 \'동양의 루르\'라고도 불려요.'),
  'shenyang/dumpling': ('라오볜 만두', '200년 전통을 자랑하는 라오볜 만두는 북방 요리를 대표하는 별미예요.'),
  'hefei/judge': ('포공사', '정의로운 판관 포청천의 고향인 이곳의 사당은 청렴함을 기리는 상징적인 장소예요.'),
  'hefei/science': ('과학 도시', '중국의 주요 대학과 연구소들이 밀집해 있는 첨단 기술의 중심지예요.'),
  'hefei/lake': ('차오후', '중국 5대 담수호 중 하나로, 맛 좋은 백어와 게 요리로 유명해요.'),
  'hefei/cake': ('루저우 참깨떡', '달콤한 소가 들어간 참깨떡은 옛 루저우 지역부터 내려오는 전통 간식이에요.'),
  'foshan/wingchun': ('영춘권', '엽문과 이소룡의 무술 뿌리인 영춘권의 본고장이에요.'),
  'foshan/lion': ('사자춤', '남부 사자춤의 수도라 불리며, 축제 때마다 화려한 사자들이 기둥 위를 뛰어다녀요.'),
  'foshan/ceramic': ('스완 도자기', '천 년의 역사를 지닌 가마에서 생동감 넘치는 스완 도자기 인형들이 지금도 만들어지고 있어요.'),
  'foshan/opera': ('광둥극', '중국 남부에서 가장 사랑받는 무대 예술인 광둥극이 바로 이곳에서 꽃피웠어요.'),
  'guiyang/pavilion': ('자슈거', '난밍강 위에 자리한 3층 누각으로, 400년 동안 구이양을 상징해 온 명소예요.'),
  'guiyang/sourfish': ('쏸탕위', '발효 토마토를 넣은 새콤한 붉은 국물에 생선을 끓여낸 구이저우의 대표 요리예요.'),
  'guiyang/waterfall': ('황궈수 폭포', '아시아 최대 규모를 자랑하는 폭포로, 웅장한 물줄기와 함께 무지개가 자주 나타나요.'),
  'guiyang/miao': ('먀오족 문화', '은 장식을 한 먀오족의 화려한 축제와 자수는 산간 마을을 더욱 아름답게 빛내줘요.'),
  'changchun/film': ('영화 도시', '중국 영화의 발상지이자 \'동양의 할리우드\'라 불리는 영화 촬영소가 이곳에 있어요.'),
  'changchun/car': ('자동차 도시', '중국 최초의 국산 자동차가 탄생한 곳으로, 명실상부한 자동차 산업의 중심지예요.'),
  'changchun/palace': ('위만황궁', '마지막 황제가 머물렀던 이 궁궐은 격동의 역사를 고스란히 간직하고 있어요.'),
  'changchun/snow': ('겨울 설경', '길고 하얀 겨울이 찾아오면 도시 곳곳이 얼음 조각과 스키장으로 반짝여요.'),
  'xining/lake': ('칭하이호', '중국 최대의 염호로, 여름이면 호수 주변을 가득 채우는 노란 유채꽃밭이 유명해요.'),
  'xining/monastery': ('타얼사', '티베트 불교 6대 사원 중 하나로, 야크 버터로 만든 정교한 조각품으로 잘 알려져 있어요.'),
  'xining/flower': ('유채꽃', '7월이 되면 고원 지대는 지평선까지 끝없이 펼쳐진 황금빛 유채꽃으로 뒤덮여요.'),
  'xining/lamb': ('야크와 양고기', '후이족과 티베트족의 손맛이 담긴 수타면과 양꼬치는 이 지역 고원 지대를 대표하는 별미예요.'),
  'guilin/karst': ('리강 카르스트 지형', '안개 속으로 솟아오른 석회암 봉우리들은 20위안 지폐 뒷면에도 그려진 절경이에요.'),
  'guilin/elephant': ('샹비산', '강물을 마시는 코끼리 모양의 바위는 구이린을 상징하는 사랑받는 명소예요.'),
  'guilin/terrace': ('룽지 다랭이논', '용의 등뼈를 닮았다고 해서 이름 붙여진 이 계단식 논은 수 세기 동안 이어진 농부들의 땀방울이 맺힌 곳이에요.'),
  'guilin/osmanthus': ('계화꽃', '계수나무 숲이라는 뜻의 지명답게 가을이 되면 도시 전체가 달콤한 계화꽃 향기로 가득 차요.'),
  'wenzhou/merchant': ('원저우 상인 정신', '중국의 유대인이라 불리는 원저우 기업가들은 전 세계를 무대로 비즈니스 네트워크를 구축하고 있어요.'),
  'wenzhou/shoe': ('신발과 가죽 산업', '전 세계에서 유통되는 수많은 가죽 신발이 바로 이 공업 도시에서 생산되고 있어요.'),
  'wenzhou/mountain': ('옌당산', '폭포와 험준한 봉우리로 유명하며, 바다 옆의 첫 번째 산이라는 찬사를 받는 곳이에요.'),
  'wenzhou/seafood': ('해산물 요리', '동중국해에서 갓 잡아 올린 오징어, 가리비, 생선은 원저우 식탁의 핵심 재료예요.'),
  'tangshan/memorial': ('지진 기념비', '1976년 대지진을 기리는 이 기념 공원은 다시 일어선 도시의 상징과도 같아요.'),
  'tangshan/coal': ('탕산 탄광', '중국 최초의 근대식 탄광과 철도가 시작된 이곳은 중국 산업의 발상지입니다.'),
  'tangshan/ceramic': ('탕산 도자기', '북방의 도자기 도시로 불리는 이곳의 본차이나는 우아한 품질로 유명합니다.'),
  'tangshan/lake': ('난후 공원', '과거 채굴장이었던 곳을 공원으로 탈바꿈시켜 도시의 녹색 허파 역할을 하고 있습니다.'),
  'anshan/steel': ('철강 도시', '중국 최대 규모의 제철소가 설립된 이곳은 명실상부한 중국의 철강 수도입니다.'),
  'anshan/jade': ('슈옌 옥', '세계 최대 규모의 옥 조각품이 있는 이곳은 중국을 대표하는 옥의 고장입니다.'),
  'anshan/mountain': ('첸산', '천 개의 연꽃 봉우리가 솟아 있다는 첸산은 사찰과 기암괴석이 어우러진 북방의 명산입니다.'),
  'anshan/spring': ('탕강쯔 온천', '천 년의 역사를 자랑하는 이곳 온천은 예로부터 황제들이 즐겨 찾던 치유의 명소입니다.'),
  'linyi/market': ('도매 시장', '중국 북부 최대의 도매 물류 허브로서 전국 각지로 다양한 상품을 공급합니다.'),
  'linyi/brush': ('서예의 고장', '서예의 성인 왕희지가 태어난 곳으로, 먹과 붓의 향기가 가득한 도시입니다.'),
  'linyi/mountain': ('멍산', '산둥성에서 두 번째로 높은 산으로, 맑은 공기와 폭포가 어우러진 천연 산소 카페입니다.'),
  'linyi/pancake': ('이멍 지엔빙', '옥수수로 얇게 부쳐낸 지엔빙은 이멍 산간 지역 사람들의 오랜 주식입니다.'),
  'cangzhou/lion': ('철사자', '1,100년의 역사를 간직한 거대한 철제 사자상은 창저우를 상징하는 자랑스러운 문화재입니다.'),
  'cangzhou/martial': ('무술의 고향', '중국 무술의 본고장으로, 수많은 무술 대가와 문파가 이곳에서 배출되었습니다.'),
  'cangzhou/canal': ('대운하', '베이징과 항저우를 잇는 대운하가 도시를 가로지르며 옛 부두의 정취를 간직하고 있습니다.'),
  'cangzhou/jujube': ('금사대추', '껍질이 얇고 달콤한 금사대추는 건과일 중에서도 으뜸으로 꼽힙니다.'),
  'nantong/textile': ('난퉁 방직성', '중국 가정용 섬유의 중심지로, 이곳에서 생산된 면직물은 전 세계로 수출되고 있어요.'),
  'nantong/mountain': ('랑산', '양쯔강 하구에 솟아 있는 다섯 개의 봉우리가 어우러진 성스러운 산으로, 많은 이들이 경치를 감상하러 찾는 곳이에요.'),
  'nantong/kite': ('반야오 연', '피리가 달려 있어 소리가 나는 \'반야오\' 연은 난퉁의 오랜 전통 공예품이에요.'),
  'nantong/school': ('근대 교육의 발상지', '기업가 장젠이 이곳에 중국 최초의 근대식 학교와 박물관을 설립했어요.'),
  'taizhou/opera': ('메이란팡', '경극의 전설적인 거장 메이란팡이 태어난 고향이에요.'),
  'taizhou/tea': ('자오차', '찜 요리와 차를 곁들여 아침을 즐기는 \'자오차\'는 타이저우의 대표적인 식문화예요.'),
  'taizhou/boat': ('친퉁 보트 축제', '봄이 되면 수백 명의 노잡이가 참여하는 보트 경주가 열려 강 위를 활기차게 만들어요.'),
  'taizhou/meatball': ('사자두', '부드러운 돼지고기로 만든 큼직한 완자인 \'사자두\'는 화이양 요리의 고전이에요.'),
  'jinhua/ham': ('진화 햄', '수백 년 전통의 방식으로 염장한 붉은빛의 진화 햄은 중국에서 가장 유명한 햄이에요.'),
  'jinhua/film': ('헝뎬 월드 스튜디오', '세계 최대 규모의 야외 촬영장으로, 수많은 시대극이 이곳에서 제작되고 있어요.'),
  'jinhua/cave': ('솽룽 동굴', '낮은 바위 문을 지나 배를 타고 들어가는 지하 동굴의 신비로운 풍경은 감탄을 자아내요.'),
  'jinhua/bridge': ('고대 석교', '아치형 석교와 물길이 어우러진 마을 풍경에서 강남 지역 특유의 우아함을 느낄 수 있어요.'),
  'wuhu/park': ('팡테 원더랜드', '중국 최대 규모의 테마파크 중 하나로, 가족 단위 방문객들에게 즐거운 추억을 선사해요.'),
  'wuhu/ironart': ('철화', '연철을 두드려 만든 우아한 \'철화\'는 300년의 역사를 자랑하는 전통 공예예요.'),
  'wuhu/rice': ('쌀의 도시', '양쯔강 변에 위치한 이 도시는 역사적으로 중국에서 가장 큰 쌀 시장이었어요.'),
  'wuhu/river': ('양쯔강 항구', '안후이성의 바닷길 관문 역할을 하는 분주한 강변 항구예요.'),
  'huangshan/peak': ('황산', '화강암 봉우리와 운해, 기이한 소나무가 어우러진 중국에서 가장 유명한 산이에요.'),
  'huangshan/village': ('훙춘 마을', '물길과 하얀 벽이 어우러진 유네스코 세계문화유산 마을로, 마치 한 폭의 그림 같아요.'),
  'huangshan/tea': ('마오펑 차', '안개 낀 산비탈에서 채취한 솜털 덮인 녹차로, 중국 10대 명차 중 하나예요.'),
  'huangshan/ink': ('후이저우 먹과 예술', '후이저우의 먹과 목조 가옥, 서예는 이 지역의 소중한 문화 유산이에요.'),
  'yichun/moon': ('밍웨산', '온천과 케이블카에서 내려다보는 풍경으로 유명한 \'밝은 달의 산\'이에요.'),
  'yichun/spring': ('온천', '희귀한 셀레늄이 풍부한 온천 덕분에 중국의 대표적인 온천 휴양지로 자리 잡았어요.'),
  'yichun/zen': ('선불교', '중국 선불교의 뿌리를 둔 산속 사찰들이 마음의 평온을 찾아줘요.'),
  'yichun/rice': ('곡창지대', '비옥한 위안허 평야는 오랫동안 장시성의 곡창지대 역할을 해왔어요.'),
  'zhangzhou/narcissus': ('수선화', '중국에서 가장 유명한 수선화 산지로, 춘절을 상징하는 꽃이기도 해요.'),
  'zhangzhou/tulou': ('객가 토루', '유네스코 세계문화유산인 거대한 원형 흙집으로, 마을 사람들이 한 지붕 아래 모여 살아요.'),
  'zhangzhou/banana': ('열대 과일', '바나나, 용안, 귤 과수원 덕분에 따뜻한 삼각주 지역은 일 년 내내 푸르러요.'),
  'zhangzhou/coast': ('둥산섬', '황금빛 해변과 어촌 마을이 어우러진 남부 해안의 진주 같은 섬이에요.'),
  'beijing/great-wall': ('만리장성', '중국 북부 국경을 지키기 위해 수세기에 걸쳐 쌓은 세계에서 가장 긴 성벽으로, 베이징 근교의 바다링 장성이 가장 유명해요.'),
  'beijing/temple': ('천단공원', '명·청 시대 황제들이 풍년을 기원하며 제사를 지내던 곳으로, 못을 하나도 쓰지 않은 둥근 지붕이 건축미의 정수로 꼽혀요.'),
  'beijing/pagoda': ('톈닝사 탑', '요나라 시대에 세워진 57m 높이의 13층 벽돌 탑으로, 베이징에서 가장 오래된 건축물 중 하나이자 천 년의 역사를 간직한 곳이에요.'),
  'beijing/opera': ('경극', '노래와 대사, 무술, 곡예가 어우러진 200년 전통의 중국 예술로, 배우의 얼굴에 그려진 화장인 \'롄푸\'를 통해 인물의 성격을 알 수 있어요.'),
};
